const e={home:"Home",riif:"RIIF",tptrm:"TPTRM",research:"Research",accidentology:"Accidentology",facial_recognition:"Facial Recognition",about_me:"About Me",linkedin:"LinkedIn",github:"GitHub"},t={title:"Lucas SALI--ORLIANGE",subtitle:"Data Science & AI Expert",intro_text:"I am a passionate developer who specializes in applying <strong>Artificial Intelligence to financial business problems</strong>. My approach is collaborative by working directly with business operators to <strong>improve existing processes and increase profitability</strong>. All my solutions are built to be <strong>robust, scalable, and efficient, focusing on clean code and rapid delivery</strong>.",projects_section:{title:"Achievements",riif:{title:"RIIF",description:"A confidential <strong>AI-powered Q&A platform</strong> that <strong>optimizes financial report preparation</strong> and strategic meetings, delivering instant and trustworthy answers to executive teams."},tptrm:{title:"TPTRM",description:"An <strong>automated contract analysis tool</strong> designed to <strong>reduce review times</strong> and minimize errors, offering an intuitive and secure user experience."},accidentology:{title:"Accidentology",description:"<strong>Accident severity prediction</strong> on over <strong>1 million cases</strong>, providing actionable analytics to enhance road safety and guide prevention policies."},research:{title:"Research",description:"Interdisciplinary study on eco-concrete, leveraging <strong>predictive models</strong> to optimize formulations and <strong>reduce environmental impact</strong>."},facial_recognition:{title:"Facial Recognition",description:"Developed a <strong>facial recognition model</strong> on a custom dataset, demonstrating expertise in the full AI model development lifecycle."}},skills_section:{title:"Skills",categories:{ai_and_data_science:{category_title:"AI & Data Science",category_description:"Mastery of data solutions for strategic business challenges.",skills:{ml:"Machine Learning",dl:"Deep Learning",nlp:"NLP",cv:"Computer Vision",tsa:"Time Series Analysis",pl:"AI Project Management"}},programming_and_tools:{category_title:"Programming & Tools",category_description:"Technical expertise for robust and scalable solutions.",skills:{py:"Python",sql:"SQL",git:"Git",docker:"Docker",linux:"Linux",vue:"Vue.js"}},professional_skills:{category_title:"Interpersonal Skills",category_description:"Communication and teamwork for successful projects.",skills:{tw:"Technical Writing",comm:"Communication",ps:"Problem Solving",res:"Research"}}}},contact_section:{title:"Get in Touch",contact_text:"Let's discuss your projects or digital innovation needs.",linkedin:"LinkedIn",github:"GitHub",email:"Email"}},i={intro_section:{title:"About Me",paragraphs:{p1:"Graduate engineer in Data Science & AI, I have delivered innovative solutions for complex challenges, from automated financial reporting to predictive modeling for sustainable industry. My commitment: design effective, robust, and high-impact tools for clients.",p2:"My academic and professional journey has enabled me to master the <strong>full lifecycle of AI/ML projects</strong>, from data preparation to deployment and stakeholder communication. I thrive in teams and dedicate my skills to performance and profitability."}},timeline_section:{title:"Journey",items:{graduate_engineer:{year:"2025",title:"Graduate Engineer - Data Science & AI",description:"Master’s degree, Data Science & AI specialization, ranked in the <strong>top 5%</strong> and recognized as <strong>Technical Valedictorian</strong>. Expertise in Machine Learning, Deep Learning, Generative AI, MLOps, and Data Visualization.",company:"ESIEE Paris",logo:"/img/esiee_logo.png"},internship_bnp:{year:"2025",title:"Internship - Data Scientist/ML Engineer",description:"Developed AI tools to automate financial analysis and contract evaluation, boosting productivity and data reliability for reporting teams.",company:"BNP Paribas IT Group",logo:"/img/bnpparibas_logo.png"},internship_research:{year:"2024",title:"Internship - Data Science Researcher",description:"R&D on eco-concrete property prediction using ML models. Authored a scientific report in English, demonstrating rigor and technical expertise.",company:"Gustave Eiffel University & ENPC",logo:"/img/gustave_eiffel_logo.png"},erasmus:{year:"2023",title:"Erasmus Semester - Engineering Sciences",description:"International engineering program at Università di Bologna, bringing openness and a global perspective.",company:"Università di Bologna",logo:"/img/unibo_logo.png"},it_technician:{year:"2022",title:"IT Technician",description:"Technical support for 700+ users, developing problem-solving and professional communication skills.",company:"Milleis Banque Privée",logo:"/img/milleis_logo.png"}}},skills_section:{title:"Skills",categories:{ai_and_data_science:{category_title:"AI & Data Science",skills:{ml:"Machine Learning",dl:"Deep Learning",genai:"Generative AI",nlp:"NLP",dm:"Data Modeling",mlops:"MLOps"}},programming_and_infrastructure:{category_title:"Programming & Infrastructure",skills:{py:"Python",r:"R",vue:"Vue.js",fastapi:"FastAPI",flask:"Flask",django:"Django",dash:"Dash",git:"Git",docker:"Docker",sql:"SQL",chroma:"ChromaDB",postgres:"PostgreSQL"}},data_science_libraries:{category_title:"Data Science Libraries & Tools",skills:{sklearn:"Scikit-Learn",pandas:"Pandas",numpy:"Numpy",tf:"TensorFlow",keras:"Keras",mt:"Multithreading",pymupdf:"PyMuPDF",seaborn:"Seaborn",plotly:"Plotly",optuna:"Optuna",langchain:"Langchain",openai:"OpenAI"}},professional_skills:{category_title:"Business & Professional Skills",skills:{pm:"Project Management",tw:"Technical Writing",ps:"Problem Solving",sc:"Stakeholder Communication",onboarding:"Onboarding"}}}}},n="Key Responsibilities & Skills",a="Ready to build the next big thing?",o="View Project",s="Let's Connect",r=JSON.parse(`{"title_project":{"accidentology":{"title":"Road Accident Severity Prediction","subtitle":"Applying Data Science to Enhance Traffic Safety","paragraphs":{"p1":"As a student project at <strong>ESIEE Paris</strong>, I undertook a comprehensive <strong>data analysis project</strong> focused on a dataset of over <strong>1 million road accidents since 2010</strong>. The primary goal was to build a predictive model that could accurately estimate the severity of an accident based on various factors, such as weather conditions, road type, and time of day.","p2":"My role involved the entire <strong>data science lifecycle</strong>, from cleaning and preprocessing the raw data to performing <strong>feature engineering</strong> to optimize model performance. By applying a range of <strong>supervised learning methods</strong>, I was able to build a robust model that provides valuable insights into traffic safety, which could inform preventative strategies. "},"skills_section":{"categories":{"data_analysis_and_modeling":{"title":"Analysis & Modeling","skills":{"fe":"Feature Engineering","sl":"Supervised Learning","me":"Model Evaluation","dv":"Visualization"}},"technical_skills":{"title":"Technical Skills","skills":{"py":"Python","pandas":"Pandas","sklearn":"Scikit-learn","xgboost":"XGBoost","lightgbm":"LightGBM","optuna":"Optuna","seaborn":"Seaborn","plotly":"Plotly"}}}},"impacts_section":{"title":"Impact & Key Contributions","categories":{"high_accuracy_model":{"title":"High-Accuracy Predictive Model","description":"Developed a supervised learning model that achieved an <strong>86% accuracy rate</strong> in predicting accident severity, providing a robust tool for traffic safety analysis."},"data_driven_insights":{"title":"Date-Driven Insights","description":"Conducted in-depth analysis on a dataset of <strong>over 1 million road accidents</strong>, identifying key factors influencing accident severity and providing actionable insights for safety initiatives."},"end_to_end_analysis":{"title":"End-to-End Analysis","description":"Managed the full data science lifecycle, from <strong>preprocessing and feature engineering</strong> to <strong>model training and comparison</strong>, demonstrating a comprehensive understanding of data analysis workflows."}}}},"riif":{"title":"RIIF: Financial Reporting Reinvented","subtitle":"AI-Driven Solution for Corporate Efficiency","paragraphs":{"p1":"In the fast-paced world of financial services, preparing for high-stakes investor briefings and executive meetings requires both speed and precision. As an <strong>intern at BNP Paribas</strong>, I developed <strong>RIIF</strong>, an intelligent solution that <strong>streamlined the process of retrieving and validating key financial data</strong>. This work empowered business teams to shift their focus from time-consuming data retrieval to strategic analysis and communication. ","p2":"My role involved close <strong>collaboration with financial reporting teams</strong> to understand their workflows and pain points. By building a tool that provides instant, verifiable answers, I helped ensure <strong>data integrity while significantly improving preparation time</strong> for major corporate events. This project demonstrates my ability to translate complex business needs into <strong>effective, secure, and user-centric technical solutions</strong>. "},"skills_section":{"categories":{"management_and_communication":{"title":"Management & Communication","skills":{"pm":"Project Management","sc":"Stakeholder Communication","cfl":"Cross-Functional Leadership","cs":"Compliance & Security"}},"technical_skills":{"title":"Technical Skills","skills":{"genai":"Generative AI","rag":"RAG","ds":"Data Science","pc":"Parsing/Chunking","py":"Python","fastapi":"FastAPI","vdb":"Vector Database","postman":"Postman"}}}},"impacts_section":{"title":"Impact & Key Contributions","categories":{"increased_productivity":{"title":"Increased Productivity","description":"Automated a critical, manual workflow, allowing teams to <strong>accelerate preparation for quarterly financial reports</strong> and investor relations meetings."},"guaranteed_data_integrity":{"title":"Guaranteed Data Integrity","description":"Engineered a <strong>secure and compliant AI solution</strong> that not only <strong>minimized human error</strong> but also guarantee the <strong>integrity of core business data</strong>, ensuring all financial information was consistent and reliable for audit and reporting."},"scalable_robust_design":{"title":"Scalable & Robust Designn","description":"Developed a <strong>scalable and maintainable system</strong> pocapable of handling large volumes of internal documents, ensuring long-term operational viability."}}}},"tptrm":{"title":"TPTRM: Accelerating Contract Analysis","subtitle":"An AI Solution for Faster, More Accurate Legal Review","paragraphs":{"p1":"During my internship at <strong>BNP Paribas IT Group</strong>, I developed a tool to <strong>automate contract analysis</strong>, a critical and time-consuming process for the legal and compliance teams. This solution, named <strong>TPTRM</strong>, streamlined the review workflow by <strong>automatically parsing documents and highlighting key clauses</strong>, significantly reducing manual effort. ","p2":"My role involved <strong>working closely with end-users</strong> to understand their pain points and ensure the tool's features directly addressed their needs. By integrating user feedback through workshops and iterative design, I created a solution that not only improved efficiency but also <strong>minimized human error</strong> and provided a <strong>more user-friendly experience</strong>. This project demonstrates my ability to build robust and scalable applications that meet complex business requirements. "},"skills_section":{"categories":{"management_and_communication":{"title":"Management & Communication","skills":{"sc":"Stakeholder Communication","ra":"Requirements Analysis","am":"Agility","ucd":"User-Centric Design"}},"technical_skills":{"title":"Technical Skills","skills":{"py":"Python","pandas":"Pandas","genai":"Generative AI","pc":"Parsing/Chunking","streamlit":"Streamlit","rag":"RAG","mt":"Multithreading"}}}},"impacts_section":{"title":"Impact & Key Contributions","categories":{"reduced_review_time":{"title":"Reduced Review Time","description":"Developed an automated contract analysis tool that <strong>cut the average review time by 75%</strong>, allowing legal and business teams to focus on critical tasks."},"increased_accuracy":{"title":"Increased Accuracy","description":"<strong>Engineered a system to automate subjective tasks</strong>, which helped <strong>significantly reduce human error</strong> and ensure data integrity, thereby minimizing compliance risks."},"enhanced_user_experience":{"title":"Enhanced User Experience","description":"Led workshops with end-users and iteratively improved the tool’s design based on feedback, resulting in a <strong>highly intuitive and user-centric solution</strong>."}}}},"research":{"title":"Applied Research: Eco-Concrete","subtitle":"Leveraging Data Science for Sustainable Engineering","paragraphs":{"p1":"During my internship as a <strong>Data Science Researcher at Gustave Eiffeil University & ENPC</strong>, I conducted interdisciplinary research on eco-concrete formulation. The project's goal was to leverage machine learning to <strong>predict the mechanical properties of concrete</strong>, helping to <strong>optimize its composition</strong> and <strong>reduce its carbon footprint</strong> by incorporating recycled materials. ","p2":"My role was to <strong>build and validate predictive models</strong> from a large dataset. I conducted a comprehensive <strong>literature review</strong> and applied advanced algorithms like XGBoost and LightGBM to identify the most impactful variables. This work demonstrates my ability to apply a <strong>rigorous scientific approach</strong> to complex problems, transforming raw data into actionable insights for sustainable engineering. "},"skills_section":{"categories":{"research_and_analysis":{"title":"Research & Analysis","skills":{"lr":"Literature Review","ht":"Hypothesis Testing","pm":"Predictive Modeling","sa":"Statistical Analysis","tw":"Scientific Writing"}},"technical_skills":{"title":"Technical Skills","skills":{"pysk":"Python & Scikit-learn","xgb":"XGBoost","lgbm":"LightGBM","de":"Data Engineering","dv":"Visualization"}}}},"impacts_section":{"title":"Impact & Key Contributions","categories":{"optimized_material_formulation":{"title":"Optimized Material Formulation","description":"Developed advanced <strong>predictive models (XGBoost, LightGBM)</strong> to estimate the mechanical properties of eco-concrete, enabling researchers to optimize material composition and <strong>reduce environmental impact</strong>."},"streamlined_research_workflow":{"title":"Streamlined Research Workflow","description":"Automated data analysis and a literature review process, which <strong>accelerated the research cycle</strong> and provided a robust framework for testing multiple hypotheses with greater efficiency."},"effective_scientific_communication":{"title":"Effective Scientific Communication","description":"Authored a <strong>comprehensive technical report in English using LaTeX</strong>, effectively communicating complex methodologies and research findings to a broader scientific audience."}}}},"facial_recognition":{"title":"Facial Recognition: A Deep Learning Case Study","subtitle":"Building a CNN-based Model from Scratch","paragraphs":{"p1":"As a student at <strong>ESIEE Paris</strong>, I undertook a project to build an <strong>end-to-end facial recognition model</strong> using a custom dataset. The challenge was to demonstrate proficiency in every step of a machine learning project, from data <strong>preparation to model deployment</strong>. I chose a unique and engaging dataset—scenes from 'Jurassic Park'—to highlight the process of working with real-world, uncurated data. ","p2":"This project required me to <strong>collect and annotate image data</strong>, perform data augmentation, and implement a <strong>Convolutional Neural Network (CNN)</strong> for training. The work showcases my practical skills in <strong>deep learning, computer vision, and problem-solving</strong>, proving my ability to turn a concept into a functional and demonstrable solution. "},"skills_section":{"categories":{"data_model_lifecycle":{"title":"Data & Model Lifecycle","skills":{"dc":"Dataset Creation","da":"Annotation","dag":"Augmentation","mt":"Training","ht":"Optimization"}},"technical_skills":{"title":"Technical Skills","skills":{"py":"Python","cv":"Computer Vision","cnn":"CNN","ocv":"OpenCV","skl":"Scikit-learn","tfk":"TensorFlow","keras":"Keras"}}}},"impacts_section":{"title":"Impact & Key Contributions","categories":{"end_to_end":{"title":"End-to-End Model Development","description":"Managed the entire machine learning lifecycle, from <strong>custom dataset creation and cleaning</strong> to <strong>model training and evaluation</strong>, demonstrating a comprehensive understanding of the process."},"robust_model":{"title":"Robust Model Performance","description":"Implemented and trained a <strong>Convolutional Neural Network (CNN)</strong> for facial recognition, achieving strong performance on a specialized dataset and validating the model's effectiveness."},"tech_proficiency":{"title":"Demonstrated Technical Proficiency","description":"Utilized key libraries like <strong>TensorFlow and Keras</strong> to build a robust and scalable model, highlighting practical skills in modern deep learning frameworks."}}}}}}`),l={nav:e,home:t,about_me:i,skills_section_title:n,project_outro:a,project_card:o,connect:s,projects:r};export{i as about_me,s as connect,l as default,t as home,e as nav,o as project_card,a as project_outro,r as projects,n as skills_section_title};
